// contrato mínimo: gerar bytes e metadados observáveis
// (o renderPdf é um adaptador para sua stack real)
export async function generatePdfArtifact({ input, renderPdf }) {
  const startedAt = new Date().toISOString();
  const pdfBytes = await renderPdf(input);

  if (!pdfBytes || pdfBytes.length < 1000) {
    throw new Error('PDF inválido: bytes insuficientes');
  }

  // contrato de rastreabilidade (ex.: log estruturado/telemetria)
  return {
    pdfBytes,
    meta: {
      startedAt,
      inputSignature: stableSignature(input),
      generatorVersion: process.env.GENERATOR_VERSION ?? 'dev',
    },
  };
}

function stableSignature(input) {
  // em produção use um hash estável (ex.: SHA-256) do payload normalizado
  return JSON.stringify(input);
}
